   217тЖТ
   218тЖТ  // Generate PM history using cold-start algorithm
   219тЖТ  const pmHistory: DemoPMHistory[] = [];
   220тЖТ  const pmCodes = ['C1', 'C2', 'C3', 'C4', 'OH'];
   221тЖТ
   222тЖТ  for (const train of trains) {
   223тЖТ    // For each PM type, calculate completed cycles based on mileage
   224тЖТ    for (const pmCode of pmCodes) {
   225тЖТ      const pmTypeKey = `${train.fleetCode}:${pmCode}`;
