   310тЖТ      currentDate = addDays(currentDate, 1);
   311тЖТ    }
   312тЖТ
   313тЖТ    // Update train's current mileage to match latest reading
   314тЖТ    train.currentMileageKm = cumulativeMileage;
   315тЖТ  }
   316тЖТ
   317тЖТ  // Generate service demand profiles
   318тЖТ  const serviceDemand: GeneratedData['serviceDemand'] = [];
   319тЖТ  for (const fleet of fleets) {
