   353тЖТ/**
   354тЖТ * Bow-Wave Scenario Generator (Chaos Monkey)
   355тЖТ *
   356тЖТ * Compresses 20% of fleet C4 maintenance into Q2 2027.
   357тЖТ * Creates a realistic maintenance clustering scenario.
   358тЖТ */
   359тЖТfunction applyBowWaveScenario(
   360тЖТ  trains: DemoTrain[],
   361тЖТ  pmHistory: DemoPMHistory[],
   362тЖТ  pmTypeMap: Map<string, { id: string; fleetId: string; intervalKm: number; intervalMonths: number }>,
   363тЖТ  rng: SeededRandom
   364тЖТ): void {
   365тЖТ  const bowWaveStart = new Date('2027-04-01');
   366тЖТ  const bowWaveEnd = new Date('2027-06-30');
   367тЖТ
   368тЖТ  // Select 20% of trains for bow-wave
   369тЖТ  const shuffledTrains = rng.shuffle(trains);
   370тЖТ  const bowWaveTrains = shuffledTrains.slice(0, Math.ceil(trains.length * 0.2));
   371тЖТ
   372тЖТ  // For each bow-wave train, adjust their last C4 to cluster in Q2 2027
   373тЖТ  for (const train of bowWaveTrains) {
   374тЖТ    const pmTypeKey = `${train.fleetCode}:C4`;
   375тЖТ    const pmType = pmTypeMap.get(pmTypeKey);
   376тЖТ    if (!pmType) continue;
   377тЖТ
   378тЖТ    // Find train's C4 history
   379тЖТ    const trainC4History = pmHistory.filter(
   380тЖТ      (pm) => pm.trainId === train.id && pm.pmCode === 'C4'
   381тЖТ    );
   382тЖТ
   383тЖТ    if (trainC4History.length > 0) {
   384тЖТ      // Adjust the most recent C4 completion to create bow-wave
   385тЖТ      const lastC4 = trainC4History[trainC4History.length - 1];
   386тЖТ
