     1тЖТ/**
     2тЖТ * MMS Bow-Wave Scenario Analyzer
     3тЖТ *
     4тЖТ * Analyzes generated demo data to:
     5тЖТ * - Project future PM events based on current mileage and history
     6тЖТ * - Identify Q2 2027 maintenance clustering (bow-wave)
     7тЖТ * - Flag 40% C4 overlap violations
     8тЖТ * - Calculate capital risk concentration ($15M threshold)
     9тЖТ * - Generate visualization data (heatmap density, Gantt bars)
    10тЖТ *
    11тЖТ * @see specs/009-demo-application.md
    12тЖТ */
    13тЖТ
    14тЖТimport { formatDate } from './generator';
    15тЖТimport type {
    16тЖТ  BowWaveAnalysis,
    17тЖТ  BowWaveScenarioOutput,
    18тЖТ  DemoPMHistory,
    19тЖТ  DemoTrain,
    20тЖТ  GanttBar,
    21тЖТ  GeneratedData,
    22тЖТ  MonthlyPMDensity,
    23тЖТ  ProjectedPM,
    24тЖТ} from './types';
    25тЖТ
    26тЖТ/** Average C4 overhaul cost in millions */
    27тЖТconst C4_COST_MILLIONS = 0.3;
    28тЖТ
    29тЖТ/** Weekly man-hour capacity (40 hours x 5 technicians) */
    30тЖТconst WEEKLY_MAN_HOUR_CAPACITY = 200;
    31тЖТ
    32тЖТ/** Critical threshold: >15 PMs per month */
    33тЖТconst CRITICAL_PM_THRESHOLD = 15;
    34тЖТ
    35тЖТ/** Overlap violation threshold: 40% of fleet */
    36тЖТconst OVERLAP_VIOLATION_THRESHOLD = 0.4;
    37тЖТ
    38тЖТ/** Add days to a date */
    39тЖТfunction addDays(date: Date, days: number): Date {
    40тЖТ  const result = new Date(date);
    41тЖТ  result.setDate(result.getDate() + days);
    42тЖТ  return result;
    43тЖТ}
    44тЖТ
    45тЖТ/** Get year-month string from date */
    46тЖТfunction getYearMonth(date: Date): string {
    47тЖТ  const year = date.getFullYear();
    48тЖТ  const month = String(date.getMonth() + 1).padStart(2, '0');
    49тЖТ  return `${year}-${month}`;
    50тЖТ}
    51тЖТ
    52тЖТ/** Get quarter string from date (Q1-Q4 YYYY) */
    53тЖТfunction getQuarter(date: Date): string {
    54тЖТ  const year = date.getFullYear();
    55тЖТ  const quarter = Math.floor(date.getMonth() / 3) + 1;
    56тЖТ  return `Q${quarter} ${year}`;
    57тЖТ}
    58тЖТ
    59тЖТ/** Calculate days between two dates */
    60тЖТfunction daysBetween(a: Date, b: Date): number {
    61тЖТ  const msPerDay = 24 * 60 * 60 * 1000;
    62тЖТ  return Math.floor((b.getTime() - a.getTime()) / msPerDay);
    63тЖТ}
    64тЖТ
    65тЖТinterface PmTypeInfo {
    66тЖТ  id: string;
    67тЖТ  pmCode: string;
    68тЖТ  intervalKm: number;
    69тЖТ  intervalMonths: number;
    70тЖТ  estimatedHours: number;
    71тЖТ  displayColor: string;
    72тЖТ}
    73тЖТ
    74тЖТ/**
    75тЖТ * Project future PM events for a train based on current state and history
    76тЖТ */
    77тЖТfunction projectTrainPMs(
    78тЖТ  train: DemoTrain,
    79тЖТ  pmTypes: PmTypeInfo[],
    80тЖТ  pmHistory: DemoPMHistory[],
    81тЖТ  horizonDate: Date,
    82тЖТ  today: Date
    83тЖТ): ProjectedPM[] {
    84тЖТ  const projections: ProjectedPM[] = [];
    85тЖТ
    86тЖТ  // Get train's PM history
    87тЖТ  const trainHistory = pmHistory.filter((pm) => pm.trainId === train.id);
    88тЖТ
    89тЖТ  for (const pmType of pmTypes) {
    90тЖТ    // Find the most recent completion of this PM type
    91тЖТ    const lastCompletion = trainHistory
    92тЖТ      .filter((pm) => pm.pmTypeId === pmType.id)
    93тЖТ      .sort((a, b) => b.completionDate.getTime() - a.completionDate.getTime())[0];
    94тЖТ
    95тЖТ    // Calculate next due date using dual triggers (mileage and time)
    96тЖТ    let nextDueDate: Date;
    97тЖТ    let nextDueMileage: number;
    98тЖТ
    99тЖТ    if (lastCompletion) {
   100тЖТ      // Calculate from last completion
   101тЖТ      const mileageSinceCompletion = train.currentMileageKm - lastCompletion.completedMileageKm;
   102тЖТ      const kmToNextPm = pmType.intervalKm - mileageSinceCompletion;
   103тЖТ      const daysToMileageDue = Math.max(0, Math.round(kmToNextPm / train.estimatedDailyKm));
   104тЖТ
   105тЖТ      const daysSinceCompletion = daysBetween(lastCompletion.completionDate, today);
   106тЖТ      const daysToTimeDue = Math.max(0, pmType.intervalMonths * 30 - daysSinceCompletion);
   107тЖТ
   108тЖТ      // Dual trigger: whichever comes first
   109тЖТ      const daysToNextPm = Math.min(daysToMileageDue, daysToTimeDue);
   110тЖТ      nextDueDate = addDays(today, daysToNextPm);
   111тЖТ      nextDueMileage = train.currentMileageKm + daysToNextPm * train.estimatedDailyKm;
   112тЖТ    } else {
   113тЖТ      // Cold start: assume PM was done at commissioning on-schedule
   114тЖТ      const daysSinceCommissioning = daysBetween(train.commissioningDate, today);
   115тЖТ      const cyclesFromCommissioning = Math.floor(train.currentMileageKm / pmType.intervalKm);
   116тЖТ      const lastPmMileage = cyclesFromCommissioning * pmType.intervalKm;
   117тЖТ
   118тЖТ      const kmToNextPm = pmType.intervalKm - (train.currentMileageKm - lastPmMileage);
   119тЖТ      const daysToMileageDue = Math.max(0, Math.round(kmToNextPm / train.estimatedDailyKm));
   120тЖТ
   121тЖТ      const monthsIntoCurrentCycle = (daysSinceCommissioning / 30) % pmType.intervalMonths;
   122тЖТ      const daysToTimeDue = Math.max(0, (pmType.intervalMonths - monthsIntoCurrentCycle) * 30);
   123тЖТ
   124тЖТ      const daysToNextPm = Math.min(daysToMileageDue, daysToTimeDue);
   125тЖТ      nextDueDate = addDays(today, daysToNextPm);
   126тЖТ      nextDueMileage = train.currentMileageKm + daysToNextPm * train.estimatedDailyKm;
   127тЖТ    }
   128тЖТ
   129тЖТ    // Project all PMs within horizon
   130тЖТ    let currentDate = nextDueDate;
   131тЖТ    let currentMileage = nextDueMileage;
   132тЖТ
   133тЖТ    while (currentDate <= horizonDate) {
   134тЖТ      projections.push({
   135тЖТ        trainId: train.id,
   136тЖТ        trainNumber: train.trainNumber,
   137тЖТ        fleetCode: train.fleetCode,
   138тЖТ        pmTypeId: pmType.id,
   139тЖТ        pmCode: pmType.pmCode,
   140тЖТ        projectedDate: new Date(currentDate),
   141тЖТ        projectedMileage: Math.round(currentMileage),
   142тЖТ        estimatedHours: pmType.estimatedHours,
   143тЖТ        displayColor: pmType.displayColor,
   144тЖТ      });
   145тЖТ
   146тЖТ      // Calculate next interval
   147тЖТ      const intervalDays = Math.round(pmType.intervalKm / train.estimatedDailyKm);
   148тЖТ      const timeDays = pmType.intervalMonths * 30;
   149тЖТ      const nextInterval = Math.min(intervalDays, timeDays);
   150тЖТ
   151тЖТ      currentDate = addDays(currentDate, nextInterval);
   152тЖТ      currentMileage += nextInterval * train.estimatedDailyKm;
   153тЖТ    }
   154тЖТ  }
   155тЖТ
   156тЖТ  return projections;
   157тЖТ}
   158тЖТ
   159тЖТ/**
   160тЖТ * Calculate monthly PM density for heatmap visualization
   161тЖТ */
   162тЖТfunction calculateMonthlyDensity(projections: ProjectedPM[]): MonthlyPMDensity[] {
   163тЖТ  const densityMap = new Map<string, MonthlyPMDensity>();
   164тЖТ
   165тЖТ  for (const pm of projections) {
   166тЖТ    const yearMonth = getYearMonth(pm.projectedDate);
   167тЖТ
   168тЖТ    if (!densityMap.has(yearMonth)) {
   169тЖТ      densityMap.set(yearMonth, {
   170тЖТ        year: pm.projectedDate.getFullYear(),
   171тЖТ        month: pm.projectedDate.getMonth() + 1,
   172тЖТ        yearMonth,
   173тЖТ        totalPMs: 0,
   174тЖТ        pmsByType: {},
   175тЖТ        isCritical: false,
   176тЖТ        manHours: 0,
   177тЖТ      });
   178тЖТ    }
   179тЖТ
   180тЖТ    const density = densityMap.get(yearMonth)!;
   181тЖТ    density.totalPMs++;
   182тЖТ    density.pmsByType[pm.pmCode] = (density.pmsByType[pm.pmCode] || 0) + 1;
   183тЖТ    density.manHours += pm.estimatedHours;
   184тЖТ  }
   185тЖТ
   186тЖТ  // Mark critical months (>15 PMs)
   187тЖТ  for (const density of densityMap.values()) {
   188тЖТ    density.isCritical = density.totalPMs > CRITICAL_PM_THRESHOLD;
   189тЖТ  }
   190тЖТ
   191тЖТ  return Array.from(densityMap.values()).sort((a, b) => a.yearMonth.localeCompare(b.yearMonth));
   192тЖТ}
   193тЖТ
   194тЖТ/**
   195тЖТ * Generate Gantt bar data for tactical visualization
   196тЖТ */
   197тЖТfunction generateGanttBars(projections: ProjectedPM[]): GanttBar[] {
   198тЖТ  return projections.map((pm) => {
   199тЖТ    // Estimate duration in days based on hours (8 hour workday)
   200тЖТ    const durationDays = Math.ceil(pm.estimatedHours / 8);
   201тЖТ    const endDate = addDays(pm.projectedDate, durationDays);
   202тЖТ
   203тЖТ    return {
   204тЖТ      trainId: pm.trainId,
   205тЖТ      trainNumber: pm.trainNumber,
   206тЖТ      fleetCode: pm.fleetCode,
   207тЖТ      pmCode: pm.pmCode,
   208тЖТ      startDate: formatDate(pm.projectedDate),
   209тЖТ      endDate: formatDate(endDate),
   210тЖТ      estimatedHours: pm.estimatedHours,
   211тЖТ      displayColor: pm.displayColor,
   212тЖТ    };
   213тЖТ  });
   214тЖТ}
   215тЖТ
   216тЖТ/**
   217тЖТ * Analyze bow-wave scenario from projected PMs
   218тЖТ */
   219тЖТfunction analyzeBowWave(projections: ProjectedPM[], fleetSize: number): BowWaveAnalysis {
   220тЖТ  // Group C4 PMs by month and quarter
   221тЖТ  const c4Projections = projections.filter((pm) => pm.pmCode === 'C4');
   222тЖТ
   223тЖТ  const c4ByMonth = new Map<string, ProjectedPM[]>();
   224тЖТ  const c4ByQuarter = new Map<string, ProjectedPM[]>();
   225тЖТ
   226тЖТ  for (const pm of c4Projections) {
   227тЖТ    const yearMonth = getYearMonth(pm.projectedDate);
   228тЖТ    const quarter = getQuarter(pm.projectedDate);
   229тЖТ
   230тЖТ    if (!c4ByMonth.has(yearMonth)) {
   231тЖТ      c4ByMonth.set(yearMonth, []);
   232тЖТ    }
   233тЖТ    c4ByMonth.get(yearMonth)!.push(pm);
   234тЖТ
   235тЖТ    if (!c4ByQuarter.has(quarter)) {
   236тЖТ      c4ByQuarter.set(quarter, []);
   237тЖТ    }
   238тЖТ    c4ByQuarter.get(quarter)!.push(pm);
   239тЖТ  }
   240тЖТ
   241тЖТ  // Find peak month
   242тЖТ  let peakMonthKey = '';
   243тЖТ  let peakMonthCount = 0;
   244тЖТ  for (const [month, pms] of c4ByMonth) {
   245тЖТ    // Count unique trains
   246тЖТ    const uniqueTrains = new Set(pms.map((pm) => pm.trainId)).size;
   247тЖТ    if (uniqueTrains > peakMonthCount) {
   248тЖТ      peakMonthCount = uniqueTrains;
   249тЖТ      peakMonthKey = month;
   250тЖТ    }
   251тЖТ  }
   252тЖТ
   253тЖТ  // Find peak quarter
   254тЖТ  let peakQuarterKey = '';
   255тЖТ  let peakQuarterCount = 0;
   256тЖТ  for (const [quarter, pms] of c4ByQuarter) {
   257тЖТ    const uniqueTrains = new Set(pms.map((pm) => pm.trainId)).size;
   258тЖТ    if (uniqueTrains > peakQuarterCount) {
   259тЖТ      peakQuarterCount = uniqueTrains;
   260тЖТ      peakQuarterKey = quarter;
   261тЖТ    }
   262тЖТ  }
   263тЖТ
   264тЖТ  // Calculate percentages
   265тЖТ  const peakMonthPercentage = fleetSize > 0 ? (peakMonthCount / fleetSize) * 100 : 0;
   266тЖТ  const peakQuarterPercentage = fleetSize > 0 ? (peakQuarterCount / fleetSize) * 100 : 0;
   267тЖТ
   268тЖТ  // Check for 40% overlap violation
   269тЖТ  const hasOverlapViolation = peakMonthPercentage >= OVERLAP_VIOLATION_THRESHOLD * 100;
   270тЖТ
   271тЖТ  // Count affected trains (those with C4 in peak quarter)
   272тЖТ  const affectedTrainIds = peakQuarterKey
   273тЖТ    ? new Set(c4ByQuarter.get(peakQuarterKey)?.map((pm) => pm.trainId) || [])
   274тЖТ    : new Set<string>();
   275тЖТ
   276тЖТ  // Calculate capital risk (C4 count in peak quarter x cost per C4)
   277тЖТ  const capitalRiskMillions = peakQuarterCount * C4_COST_MILLIONS;
   278тЖТ
   279тЖТ  // Calculate man-hour capacity analysis for peak week
   280тЖТ  const peakMonthPMs = c4ByMonth.get(peakMonthKey) || [];
   281тЖТ  const peakMonthHours = peakMonthPMs.reduce((sum, pm) => sum + pm.estimatedHours, 0);
   282тЖТ  const peakWeekHours = peakMonthHours / 4; // Approximate 4 weeks per month
   283тЖТ  const overloadPercentage =
   284тЖТ    WEEKLY_MAN_HOUR_CAPACITY > 0
   285тЖТ      ? ((peakWeekHours - WEEKLY_MAN_HOUR_CAPACITY) / WEEKLY_MAN_HOUR_CAPACITY) * 100
   286тЖТ      : 0;
   287тЖТ
   288тЖТ  // Determine risk level
   289тЖТ  let riskLevel: BowWaveAnalysis['riskLevel'];
   290тЖТ  if (hasOverlapViolation || capitalRiskMillions >= 15) {
   291тЖТ    riskLevel = 'CRITICAL';
   292тЖТ  } else if (peakMonthPercentage >= 30 || capitalRiskMillions >= 10) {
   293тЖТ    riskLevel = 'HIGH';
   294тЖТ  } else if (peakMonthPercentage >= 20 || capitalRiskMillions >= 5) {
   295тЖТ    riskLevel = 'MEDIUM';
   296тЖТ  } else {
   297тЖТ    riskLevel = 'LOW';
   298тЖТ  }
   299тЖТ
   300тЖТ  return {
   301тЖТ    peakMonth: {
   302тЖТ      yearMonth: peakMonthKey || 'N/A',
   303тЖТ      c4Count: peakMonthCount,
   304тЖТ      percentage: Math.round(peakMonthPercentage * 10) / 10,
   305тЖТ    },
   306тЖТ    peakQuarter: {
   307тЖТ      quarter: peakQuarterKey || 'N/A',
   308тЖТ      c4Count: peakQuarterCount,
   309тЖТ      percentage: Math.round(peakQuarterPercentage * 10) / 10,
   310тЖТ    },
   311тЖТ    hasOverlapViolation,
   312тЖТ    affectedTrainCount: affectedTrainIds.size,
   313тЖТ    capitalRiskMillions: Math.round(capitalRiskMillions * 10) / 10,
   314тЖТ    capacityAnalysis: {
   315тЖТ      peakWeekHours: Math.round(peakWeekHours),
   316тЖТ      weeklyCapacity: WEEKLY_MAN_HOUR_CAPACITY,
   317тЖТ      overloadPercentage: Math.round(overloadPercentage),
   318тЖТ    },
   319тЖТ    riskLevel,
   320тЖТ  };
   321тЖТ}
   322тЖТ
   323тЖТexport interface AnalyzerConfig {
   324тЖТ  /** Analysis horizon in years (default: 3 for Q2 2027 from late 2026) */
   325тЖТ  horizonYears?: number;
   326тЖТ}
   327тЖТ
   328тЖТ/**
   329тЖТ * Analyze bow-wave scenario from generated demo data
   330тЖТ *
   331тЖТ * This function:
   332тЖТ * 1. Projects future PM events based on current mileage and history
   333тЖТ * 2. Calculates monthly PM density for heatmap visualization
   334тЖТ * 3. Identifies peak C4 clustering (Q2 2027 scenario)
   335тЖТ * 4. Flags 40% overlap violations
   336тЖТ * 5. Calculates capital risk and capacity overload
   337тЖТ *
   338тЖТ * @param data - Generated demo data from generateDemoData()
   339тЖТ * @param config - Analyzer configuration
   340тЖТ * @returns Complete bow-wave scenario analysis output
   341тЖТ */
   342тЖТexport function analyzeBowWaveScenario(
   343тЖТ  data: GeneratedData,
   344тЖТ  config: AnalyzerConfig = {}
   345тЖТ): BowWaveScenarioOutput {
   346тЖТ  const { horizonYears = 3 } = config;
   347тЖТ
   348тЖТ  const today = new Date();
   349тЖТ  today.setHours(0, 0, 0, 0);
   350тЖТ
   351тЖТ  const horizonDate = new Date(today);
   352тЖТ  horizonDate.setFullYear(horizonDate.getFullYear() + horizonYears);
   353тЖТ
   354тЖТ  // Build PM type lookup by fleet
   355тЖТ  const pmTypesByFleet = new Map<string, PmTypeInfo[]>();
   356тЖТ  for (const pmType of data.pmTypes) {
   357тЖТ    const fleet = data.fleets.find((f) => f.id === pmType.fleetId);
   358тЖТ    if (fleet) {
   359тЖТ      if (!pmTypesByFleet.has(fleet.code)) {
   360тЖТ        pmTypesByFleet.set(fleet.code, []);
   361тЖТ      }
   362тЖТ      pmTypesByFleet.get(fleet.code)!.push({
   363тЖТ        id: pmType.id,
   364тЖТ        pmCode: pmType.pmCode,
   365тЖТ        intervalKm: pmType.intervalKm,
   366тЖТ        intervalMonths: pmType.intervalMonths,
   367тЖТ        estimatedHours: pmType.estimatedHours,
   368тЖТ        displayColor: pmType.displayColor,
   369тЖТ      });
   370тЖТ    }
   371тЖТ  }
   372тЖТ
   373тЖТ  // Project PMs for all trains
   374тЖТ  const allProjections: ProjectedPM[] = [];
   375тЖТ  for (const train of data.trains) {
